    next(f); wh=next(f).split(); w,h=int(wh[0]),int(wh[1]); next(f)
    ref = list(map(int, f.read().split()))

fov = 900.0

# For a given set of parameters, compute the floor color at (x,y)
def floor_color(x, y, d, freq, xoff, zoff, inv):
    dy = -(y - 900.0) / fov
    if dy >= 0:
        return None
    Z = d / (-dy)
    X = (x - 1200.0) * Z / fov
    ix = int(math.floor(X * freq + xoff))
    iz = int(math.floor(Z * freq + zoff))
    return (ix + iz + inv) & 1

# Search for parameters that match all boundary positions
print("Searching for floor parameters...")

# Collect actual boundary positions
boundaries = {}
for y in range(910, 1400, 10):
    prev = None
    bounds = []
